const fs = require('fs');
const path = require('path');

// 1. Update scripts/lib/config.mjs
const configPath = 'scripts/lib/config.mjs';
let configContent = fs.readFileSync(configPath, 'utf8');

const newConfigExport = `
/** Get the learning vault root path */
export function getLearningVaultRoot() {
  return process.env.LEARNING_VAULT_ROOT || resolve(VAULT_ROOT, '..', 'Learning_Vault');
}

/** Get the learning root path */
export function getLearningRoot() {
  return resolve(getLearningVaultRoot(), '11_Learning');
}
`;

if (!configContent.includes('getLearningRoot')) {
  configContent += newConfigExport;
  fs.writeFileSync(configPath, configContent);
  console.log('Updated config.mjs');
}

// 2. Update scripts/dashboard/server.mjs
const serverPath = 'scripts/dashboard/server.mjs';
let serverContent = fs.readFileSync(serverPath, 'utf8');

serverContent = serverContent.replace(
  /import \{ getVaultRoot, getPullsDir, getSignalsDir, listSources, SOURCES \} from '\.\.\/lib\/config\.mjs';/,
  `import { getVaultRoot, getLearningRoot, getPullsDir, getSignalsDir, listSources, SOURCES } from '../lib/config.mjs';`
);

serverContent = serverContent.replace(
  /const dailyPath = join\(getVaultRoot\(\), '11_Learning',/g,
  `const dailyPath = join(getLearningRoot(),`
);
serverContent = serverContent.replace(
  /const wildcardsDir = join\(getVaultRoot\(\), '11_Learning',/g,
  `const wildcardsDir = join(getLearningRoot(),`
);
serverContent = serverContent.replace(
  /const filePath = join\(getVaultRoot\(\), '11_Learning',/g,
  `const filePath = join(getLearningRoot(),`
);
serverContent = serverContent.replace(
  /const checksDir = join\(getVaultRoot\(\), '11_Learning',/g,
  `const checksDir = join(getLearningRoot(),`
);
fs.writeFileSync(serverPath, serverContent);
console.log('Updated server.mjs');

// 3. Update scripts/learning-session.mjs
const sessionPath = 'scripts/learning-session.mjs';
let sessionContent = fs.readFileSync(sessionPath, 'utf8');

sessionContent = sessionContent.replace(
  /import \{ resolve, join, relative, sep, basename \} from 'path';\nimport \{ readFolder, readNote \} from '\.\/lib\/frontmatter\.mjs';/,
  `import { resolve, join, relative, sep, basename } from 'path';\nimport { getLearningVaultRoot, getLearningRoot } from './lib/config.mjs';\nimport { readFolder, readNote } from './lib/frontmatter.mjs';`
);

sessionContent = sessionContent.replace(
  /const LEARNING_ROOT = join\(VAULT_ROOT, '11_Learning'\);/,
  `const LEARNING_VAULT_ROOT = getLearningVaultRoot();\nconst LEARNING_ROOT = getLearningRoot();`
);

sessionContent = sessionContent.replace(
  /function toVaultRelative\(filePath\) \{\n  return relative\(VAULT_ROOT, filePath\)\.split\(sep\)\.join\('\/'\);\n\}/,
  `function toVaultRelative(filePath) {
  if (filePath.startsWith(LEARNING_VAULT_ROOT)) {
    return relative(LEARNING_VAULT_ROOT, filePath).split(sep).join('/');
  }
  return relative(VAULT_ROOT, filePath).split(sep).join('/');
}`
);

fs.writeFileSync(sessionPath, sessionContent);
console.log('Updated learning-session.mjs');
